INSERT INTO students (user_id, lrn, student_number, first_name, last_name, middle_name, birthdate, age, sex, address, contact_no, guardian_name, guardian_contact, previous_school, status, created_at, updated_at)
SELECT
    u.Id,
    CONCAT('LRN-', LPAD(seq.n, 4, '0')),
    CONCAT('STU-', LPAD(1000 + seq.n, 4, '0')),
    CONCAT('Student', LPAD(seq.n, 2, '0')),
    CONCAT('Learner', LPAD(seq.n, 2, '0')),
    NULL,
    DATE_ADD('2011-06-01', INTERVAL seq.n DAY),
    13 + MOD(seq.n, 4),
    CASE WHEN MOD(seq.n, 2) = 0 THEN 'F' ELSE 'M' END,
    CONCAT('Purok ', seq.n),
    CONCAT('0918', LPAD(seq.n, 7, '0')),
    CONCAT('Guardian ', LPAD(seq.n, 2, '0')),
    CONCAT('0999', LPAD(seq.n, 7, '0')),
    CASE WHEN MOD(seq.n, 6) = 0 THEN CONCAT('Previous School ', LPAD(seq.n, 2, '0')) ELSE NULL END,
    CASE
        WHEN seq.n = 8 THEN 'LOCKED'
        WHEN seq.n = 10 THEN 'INACTIVE'
        ELSE 'ACTIVE'
    END,
    UTC_TIMESTAMP(6),
    UTC_TIMESTAMP(6)
FROM (
    SELECT @rownum_students := @rownum_students + 1 AS n
    FROM information_schema.COLUMNS, (SELECT @rownum_students := 0) init_students
    LIMIT 40
) AS seq
JOIN users u ON u.username = CONCAT('student', LPAD(seq.n, 2, '0'));

