INSERT INTO class_offerings (school_year_id, section_id, subject_id, teacher_id, curriculum_id, status, room, created_at, updated_at)
SELECT
    @sy_active,
    seq.section_id,
    seq.subject_id,
    CASE MOD(seq.rn - 1, 3)
        WHEN 0 THEN @t1
        WHEN 1 THEN @t2
        ELSE @t3
    END AS teacher_id,
    @cur,
    CASE WHEN seq.rn <= 6 THEN 'FINALIZED' ELSE 'ACTIVE' END AS status,
    CASE MOD(seq.rn - 1, 4)
        WHEN 0 THEN 'RM-201'
        WHEN 1 THEN 'RM-202'
        WHEN 2 THEN 'SCI-1'
        ELSE 'COMP-1'
    END AS room,
    UTC_TIMESTAMP(6),
    UTC_TIMESTAMP(6)
FROM (
    SELECT
        sec.Id AS section_id,
        cs.subject_id,
        ROW_NUMBER() OVER (ORDER BY sec.Id, subj.code) AS rn
    FROM sections sec
    JOIN curriculum_subjects cs
        ON cs.curriculum_id = @cur
       AND cs.grade_level_id = sec.grade_level_id
    JOIN subjects subj ON subj.Id = cs.subject_id
    WHERE sec.school_year_id = @sy_active
) AS seq;

-- Schedules for active year offerings only
SET @rm201 := (SELECT Id FROM rooms WHERE code = 'RM-201' LIMIT 1);
SET @rm202 := (SELECT Id FROM rooms WHERE code = 'RM-202' LIMIT 1);
SET @scilab := (SELECT Id FROM rooms WHERE code = 'SCI-1' LIMIT 1);
SET @complab := (SELECT Id FROM rooms WHERE code = 'COMP-1' LIMIT 1);
SET @p1 := (SELECT Id FROM time_slots WHERE code = 'P1' LIMIT 1);
SET @p2 := (SELECT Id FROM time_slots WHERE code = 'P2' LIMIT 1);
SET @p3 := (SELECT Id FROM time_slots WHERE code = 'P3' LIMIT 1);
SET @p4 := (SELECT Id FROM time_slots WHERE code = 'P4' LIMIT 1);
SET @p5 := (SELECT Id FROM time_slots WHERE code = 'P5' LIMIT 1);
SET @p6 := (SELECT Id FROM time_slots WHERE code = 'P6' LIMIT 1);

SET @off_eng7_emerald := (SELECT Id FROM class_offerings WHERE school_year_id = @sy_active AND section_id = @sec7a AND subject_id = @sub_eng7 LIMIT 1);
INSERT INTO class_schedules (class_offering_id, room_id, time_slot_id, day_of_week, start_time, end_time, created_at, updated_at)
SELECT
    seq.class_offering_id,
    CASE MOD(seq.rn - 1, 4)
        WHEN 0 THEN @rm201
        WHEN 1 THEN @rm202
        WHEN 2 THEN @scilab
        ELSE @complab
    END AS room_id,
    ts.Id AS time_slot_id,
    1 + MOD(seq.rn - 1, 5) AS day_of_week,
    ts.start_time,
    ts.end_time,
    UTC_TIMESTAMP(6),
    UTC_TIMESTAMP(6)
FROM (
    SELECT
        co.Id AS class_offering_id,
        ROW_NUMBER() OVER (ORDER BY co.section_id, co.subject_id, co.Id) AS rn
    FROM class_offerings co
    WHERE co.school_year_id = @sy_active
) AS seq
JOIN time_slots ts ON ts.Id = CASE MOD(seq.rn - 1, 6)
    WHEN 0 THEN @p1
    WHEN 1 THEN @p2
    WHEN 2 THEN @p3
    WHEN 3 THEN @p4
    WHEN 4 THEN @p5
    ELSE @p6
END;

