INSERT INTO class_students (class_offering_id, student_id, enrollment_id, status, created_at, updated_at)
SELECT o.Id, e.student_id, e.Id, 'ACTIVE', UTC_TIMESTAMP(6), UTC_TIMESTAMP(6)
FROM enrollments e
JOIN class_offerings o ON o.section_id = e.section_id AND o.school_year_id = e.school_year_id
WHERE e.status = 'ENROLLED';

-- Keep a few non-active cases for enrollment and roster workflows
UPDATE enrollments e
JOIN students s ON s.Id = e.student_id
SET
    e.status = CASE
        WHEN s.lrn IN ('LRN-0010', 'LRN-0029') THEN 'DROPPED'
        WHEN s.lrn IN ('LRN-0039') THEN 'TRANSFERRED_OUT'
        ELSE e.status
    END,
    e.updated_at = UTC_TIMESTAMP(6)
WHERE e.school_year_id = @sy_active
  AND s.lrn IN ('LRN-0010', 'LRN-0029', 'LRN-0039');

UPDATE class_students cs
JOIN enrollments e ON e.Id = cs.enrollment_id
SET
    cs.status = IF(e.status = 'ENROLLED', 'ACTIVE', 'DROPPED'),
    cs.updated_at = UTC_TIMESTAMP(6)
WHERE e.school_year_id = @sy_active;

