SET @wt_qa := (SELECT weight FROM grade_components WHERE Id = @qa_component_id LIMIT 1);

-- Q1: full assessment setup for all active-year offerings (all components)
INSERT INTO assessments (class_offering_id, grading_period_id, component_id, title, max_score, date_given, created_at, updated_at)
SELECT
    seq.class_offering_id,
    @q1,
    gc.Id,
    CONCAT('Q1 ', REPLACE(gc.name, '_', ' '), ' - ', seq.subject_code),
    CASE gc.name
        WHEN 'WRITTEN_WORKS' THEN 50.00
        WHEN 'PERFORMANCE_TASKS' THEN 100.00
        ELSE 60.00
    END AS max_score,
    DATE_ADD('2025-07-01', INTERVAL (seq.rn - 1) DAY),
    UTC_TIMESTAMP(6),
    UTC_TIMESTAMP(6)
FROM (
    SELECT
        co.Id AS class_offering_id,
        subj.code AS subject_code,
        ROW_NUMBER() OVER (ORDER BY co.section_id, co.subject_id, co.Id) AS rn
    FROM class_offerings co
    JOIN subjects subj ON subj.Id = co.subject_id
    WHERE co.school_year_id = @sy_active
) AS seq
JOIN grade_components gc ON gc.is_active = 1;

-- Q2: partial assessment setup (first 8 offerings) for realistic in-progress grading
INSERT INTO assessments (class_offering_id, grading_period_id, component_id, title, max_score, date_given, created_at, updated_at)
SELECT
    seq.class_offering_id,
    @q2,
    gc.Id,
    CONCAT('Q2 ', REPLACE(gc.name, '_', ' '), ' - ', seq.subject_code),
    CASE gc.name
        WHEN 'WRITTEN_WORKS' THEN 40.00
        WHEN 'PERFORMANCE_TASKS' THEN 100.00
        ELSE 60.00
    END AS max_score,
    DATE_ADD('2025-09-01', INTERVAL (seq.rn - 1) DAY),
    UTC_TIMESTAMP(6),
    UTC_TIMESTAMP(6)
FROM (
    SELECT
        co.Id AS class_offering_id,
        subj.code AS subject_code,
        ROW_NUMBER() OVER (ORDER BY co.section_id, co.subject_id, co.Id) AS rn
    FROM class_offerings co
    JOIN subjects subj ON subj.Id = co.subject_id
    WHERE co.school_year_id = @sy_active
) AS seq
JOIN grade_components gc ON gc.is_active = 1
WHERE seq.rn <= 8;

-- Scores linked to every assessment/student relationship in the roster
INSERT INTO assessment_scores (assessment_id, student_id, score, created_at, updated_at)
SELECT
    a.Id,
    cs.student_id,
    ROUND(a.max_score * (0.72 + (MOD(cs.student_id + a.Id, 23) / 100)), 2) AS score,
    UTC_TIMESTAMP(6),
    UTC_TIMESTAMP(6)
FROM assessments a
JOIN class_students cs ON cs.class_offering_id = a.class_offering_id
WHERE a.grading_period_id = @q1;

INSERT INTO assessment_scores (assessment_id, student_id, score, created_at, updated_at)
SELECT
    a.Id,
    cs.student_id,
    ROUND(a.max_score * (0.78 + (MOD(cs.student_id + a.Id, 17) / 100)), 2) AS score,
    UTC_TIMESTAMP(6),
    UTC_TIMESTAMP(6)
FROM assessments a
JOIN class_students cs ON cs.class_offering_id = a.class_offering_id
WHERE a.grading_period_id = @q2
  AND cs.status = 'ACTIVE';

-- Grades are derived from assessment scores for each class/student/quarter
INSERT INTO student_grades (class_offering_id, grading_period_id, student_id, written_works, performance_tasks, quarterly_assessment, quarter_grade, submitted_at, created_at, updated_at)
SELECT
    component_rollup.class_offering_id,
    component_rollup.grading_period_id,
    component_rollup.student_id,
    ROUND(MAX(CASE WHEN component_rollup.component_name = 'WRITTEN_WORKS' THEN component_rollup.component_grade END), 2) AS written_works,
    ROUND(MAX(CASE WHEN component_rollup.component_name = 'PERFORMANCE_TASKS' THEN component_rollup.component_grade END), 2) AS performance_tasks,
    ROUND(MAX(CASE WHEN component_rollup.component_name = 'QUARTERLY_ASSESSMENT' THEN component_rollup.component_grade END), 2) AS quarterly_assessment,
    ROUND(
        COALESCE(MAX(CASE WHEN component_rollup.component_name = 'WRITTEN_WORKS' THEN component_rollup.component_grade END), 0) * @wt_ww
      + COALESCE(MAX(CASE WHEN component_rollup.component_name = 'PERFORMANCE_TASKS' THEN component_rollup.component_grade END), 0) * @wt_pt
      + COALESCE(MAX(CASE WHEN component_rollup.component_name = 'QUARTERLY_ASSESSMENT' THEN component_rollup.component_grade END), 0) * @wt_qa,
        2
    ) AS quarter_grade,
    UTC_TIMESTAMP(6),
    UTC_TIMESTAMP(6),
    UTC_TIMESTAMP(6)
FROM (
    SELECT
        a.class_offering_id,
        a.grading_period_id,
        sc.student_id,
        gc.name AS component_name,
        ROUND((AVG(sc.score) / NULLIF(MAX(a.max_score), 0)) * 100, 2) AS component_grade
    FROM assessments a
    JOIN grade_components gc ON gc.Id = a.component_id
    JOIN assessment_scores sc ON sc.assessment_id = a.Id
    GROUP BY a.class_offering_id, a.grading_period_id, sc.student_id, gc.name
) AS component_rollup
GROUP BY component_rollup.class_offering_id, component_rollup.grading_period_id, component_rollup.student_id;

INSERT INTO attendance_sessions (class_offering_id, session_date, created_at, updated_at)
SELECT Id, DATE_SUB(CURDATE(), INTERVAL 3 DAY), UTC_TIMESTAMP(6), UTC_TIMESTAMP(6) FROM class_offerings WHERE school_year_id = @sy_active
UNION ALL
SELECT Id, DATE_SUB(CURDATE(), INTERVAL 2 DAY), UTC_TIMESTAMP(6), UTC_TIMESTAMP(6) FROM class_offerings WHERE school_year_id = @sy_active
UNION ALL
SELECT Id, DATE_SUB(CURDATE(), INTERVAL 1 DAY), UTC_TIMESTAMP(6), UTC_TIMESTAMP(6) FROM class_offerings WHERE school_year_id = @sy_active;

SET @admin_uid := (SELECT Id FROM users WHERE username = 'admin' LIMIT 1);
INSERT INTO attendance_records (attendance_session_id, student_id, marked_by_user_id, status, reason, created_at, updated_at)
SELECT s.Id, cs.student_id, @admin_uid,
       CASE
           WHEN (cs.student_id + DAY(s.session_date)) % 11 = 0 THEN 'ABSENT'
           WHEN (cs.student_id + DAY(s.session_date)) % 7 = 0 THEN 'LATE'
           ELSE 'PRESENT'
       END,
       CASE
           WHEN (cs.student_id + DAY(s.session_date)) % 11 = 0 THEN 'Sick'
           WHEN (cs.student_id + DAY(s.session_date)) % 7 = 0 THEN 'Transport delay'
           ELSE NULL
       END,
       UTC_TIMESTAMP(6), UTC_TIMESTAMP(6)
FROM attendance_sessions s
JOIN class_students cs ON cs.class_offering_id = s.class_offering_id
WHERE cs.status = 'ACTIVE';

