-- Student requirements workflow data
INSERT INTO student_requirements (student_id, requirement_name, is_submitted, submitted_at, notes, verified_by_user_id, created_at, updated_at)
SELECT
    seeded.student_id,
    seeded.requirement_name,
    seeded.is_submitted,
    CASE
        WHEN seeded.is_submitted = 1 THEN DATE_SUB(UTC_TIMESTAMP(6), INTERVAL MOD(seeded.student_id + seeded.order_no, 12) DAY)
        ELSE NULL
    END AS submitted_at,
    CASE
        WHEN seeded.requirement_name = 'Birth Certificate' THEN 'Verified during enrollment'
        WHEN seeded.is_submitted = 1 THEN 'Submitted'
        ELSE 'Pending submission'
    END AS notes,
    @admin_uid,
    UTC_TIMESTAMP(6),
    UTC_TIMESTAMP(6)
FROM (
    SELECT
        s.Id AS student_id,
        req.order_no,
        req.requirement_name,
        CASE req.requirement_name
            WHEN 'Birth Certificate' THEN 1
            WHEN 'Good Moral Certificate' THEN CASE WHEN MOD(s.Id, 4) = 0 THEN 0 ELSE 1 END
            ELSE CASE WHEN MOD(s.Id, 5) IN (0, 1) THEN 0 ELSE 1 END
        END AS is_submitted
    FROM students s
    CROSS JOIN (
        SELECT 1 AS order_no, 'Birth Certificate' AS requirement_name
        UNION ALL
        SELECT 2 AS order_no, 'Good Moral Certificate' AS requirement_name
        UNION ALL
        SELECT 3 AS order_no, 'Form 137' AS requirement_name
    ) AS req
) AS seeded;

